package com.example.pricing_calculation.config;
import com.example.pricing_calculation.domain.UserAccount;import com.example.pricing_calculation.repository.UserAccountRepository;import com.example.pricing_calculation.service.AuditLogService;import jakarta.servlet.*;import jakarta.servlet.http.*;import java.io.IOException;import java.util.Set;import org.springframework.security.core.Authentication;import org.springframework.security.core.context.SecurityContextHolder;import org.springframework.stereotype.Component;import org.springframework.web.filter.OncePerRequestFilter;
@Component public class MutationAuditFilter extends OncePerRequestFilter {private static final Set<String>METHODS=Set.of("POST","PUT","PATCH","DELETE");private final UserAccountRepository users;private final AuditLogService logs;public MutationAuditFilter(UserAccountRepository users,AuditLogService logs){this.users=users;this.logs=logs;}@Override protected void doFilterInternal(HttpServletRequest request,HttpServletResponse response,FilterChain chain)throws ServletException,IOException{chain.doFilter(request,response);if(METHODS.contains(request.getMethod())&&response.getStatus()<400&&!request.getRequestURI().startsWith("/api/auth")){Authentication a=SecurityContextHolder.getContext().getAuthentication();if(a!=null&&a.isAuthenticated()&&a.getPrincipal()instanceof Long id){UserAccount user=users.findById(id).orElse(null);logs.record(user,request.getMethod()+" "+request.getRequestURI(),"API",null);}}}}
